#!/usr/bin/env python3# -*- coding: utf-8 -*-import jsonimport osimport loggingimport mathfrom typing import Dict, List, Optional, Tuplelogger = logging.getLogger(__name__)CACHE_FILE = "data/zone_params_cache.json"class ZoneParamsCollector:    """    Class for collecting parameters of map sheets for Tver region    """        ZONES_BASE = {        '4': {            'epsg': 28404,            'name': 'Zone 4 (SK-42)',            'central_meridian': 21,            'false_easting': 500000,            'false_northing': 0,            'scale_factor': 1.0,            'latitude_of_origin': 0        },        '5': {            'epsg': 28405,            'name': 'Zone 5 (SK-42)',            'central_meridian': 27,            'false_easting': 500000,            'false_northing': 0,            'scale_factor': 1.0,            'latitude_of_origin': 0        },        '6': {            'epsg': 28406,            'name': 'Zone 6 (SK-42)',            'central_meridian': 33,            'false_easting': 500000,            'false_northing': 0,            'scale_factor': 1.0,            'latitude_of_origin': 0        },        '7': {            'epsg': 28407,            'name': 'Zone 7 (SK-42)',            'central_meridian': 39,            'false_easting': 500000,            'false_northing': 0,            'scale_factor': 1.0,            'latitude_of_origin': 0        },        '8': {            'epsg': 28408,            'name': 'Zone 8 (SK-42)',            'central_meridian': 45,            'false_easting': 500000,            'false_northing': 0,            'scale_factor': 1.0,            'latitude_of_origin': 0        },        '9': {            'epsg': 28409,            'name': 'Zone 9 (SK-42)',            'central_meridian': 51,            'false_easting': 500000,            'false_northing': 0,            'scale_factor': 1.0,            'latitude_of_origin': 0        }    }    ZONE_OFFSETS = {        '4': {            'offset_x': 6100000,            'offset_y': 5300000,            'dx': 805,            'dy': 45        },        '5': {            'offset_x': 6200000,            'offset_y': 5500000,            'dx': 807,            'dy': 83        },        '6': {            'offset_x': 6200000,            'offset_y': 6500000,            'dx': 802,            'dy': 34        },        '7': {            'offset_x': 6210000,            'offset_y': 6650000,            'dx': 801,            'dy': -13        },        '8': {            'offset_x': 6220000,            'offset_y': 6800000,            'dx': 800,            'dy': -25        },        '9': {            'offset_x': 6230000,            'offset_y': 6950000,            'dx': 799,            'dy': -35        }    }    TVER_SHEETS = [        {'sheet': 'O-35-21', 'zone': '5'},        {'sheet': 'O-35-22', 'zone': '5'},        {'sheet': 'O-35-23', 'zone': '5'},        {'sheet': 'O-35-24', 'zone': '5'},        {'sheet': 'O-35-25', 'zone': '5'},        {'sheet': 'O-35-26', 'zone': '5'},        {'sheet': 'O-35-27', 'zone': '5'},        {'sheet': 'O-35-28', 'zone': '5'},        {'sheet': 'O-36-141', 'zone': '6'},        {'sheet': 'O-36-142', 'zone': '6'},        {'sheet': 'O-36-143', 'zone': '6'},        {'sheet': 'O-36-144', 'zone': '6'},        {'sheet': 'O-36-145', 'zone': '6'},        {'sheet': 'N-36-17', 'zone': '6'},        {'sheet': 'N-36-18', 'zone': '6'},        {'sheet': 'N-36-19', 'zone': '6'},        {'sheet': 'N-36-20', 'zone': '6'},        {'sheet': 'N-36-21', 'zone': '6'},        {'sheet': 'O-37-105', 'zone': '7'},        {'sheet': 'O-37-106', 'zone': '7'},        {'sheet': 'O-37-107', 'zone': '7'},        {'sheet': 'O-37-108', 'zone': '7'},        {'sheet': 'N-37-82', 'zone': '7'},        {'sheet': 'N-37-83', 'zone': '7'},        {'sheet': 'N-37-84', 'zone': '7'},        {'sheet': 'N-37-85', 'zone': '7'},        {'sheet': 'O-38-105', 'zone': '8'},        {'sheet': 'N-38-82', 'zone': '8'},        {'sheet': 'P-38-122', 'zone': '8'},        {'sheet': 'O-39-105', 'zone': '9'},        {'sheet': 'P-39-122', 'zone': '9'}    ]    def __init__(self):        self.cache = self._load_cache()    def _load_cache(self) -> Dict:        if os.path.exists(CACHE_FILE):            try:                with open(CACHE_FILE, 'r', encoding='utf-8') as f:                    return json.load(f)            except Exception as e:                logger.error(f"Cache load error: {e}")        return {}    def _save_cache(self):        os.makedirs(os.path.dirname(CACHE_FILE), exist_ok=True)        try:            with open(CACHE_FILE, 'w', encoding='utf-8') as f:                json.dump(self.cache, f, ensure_ascii=False, indent=2)            logger.info(f"Cache saved: {CACHE_FILE}")        except Exception as e:            logger.error(f"Cache save error: {e}")    def get_zone_params(self, zone_number: str) -> Optional[Dict]:        return self.ZONES_BASE.get(zone_number)    def get_zone_offsets(self, zone_number: str) -> Optional[Dict]:        return self.ZONE_OFFSETS.get(zone_number)    def get_sheet_params(self, sheet_name: str) -> Optional[Dict]:        for sheet in self.TVER_SHEETS:            if sheet['sheet'].upper() == sheet_name.upper():                zone_params = self.get_zone_params(sheet['zone'])                if zone_params:                    return {                        'sheet': sheet['sheet'],                        'zone': sheet['zone'],                        'central_meridian': zone_params['central_meridian'],                        'epsg': zone_params['epsg']                    }        return None    def calculate_coordinates(self, x: float, y: float, zone_number: str, sheet_name: str = None) -> Dict:        result = {            'x': x,            'y': y,            'zone_number': zone_number,            'sheet': sheet_name,            'success': False,            'errors': []        }        zone_params = self.get_zone_params(zone_number)        if not zone_params:            result['errors'].append(f"Zone {zone_number} not found")            return result        offsets = self.get_zone_offsets(zone_number)        if not offsets:            result['errors'].append(f"Offsets for zone {zone_number} not found")            return result        x_full = offsets['offset_x'] + x        y_full = offsets['offset_y'] + y        result['x_full'] = x_full        result['y_full'] = y_full        x_sk42 = x_full + offsets['dx']        y_sk42 = y_full + offsets['dy']        result['x_sk42'] = x_sk42        result['y_sk42'] = y_sk42        lat = x_sk42 / 111000        y_local = y_sk42 - (int(zone_number) * 1000000)        lon = zone_params['central_meridian'] + (y_local / 85000)        result['latitude'] = lat        result['longitude'] = lon        result['success'] = True        return result    def detect_zone_by_coordinates(self, x: float, y: float, zone_hint: str = None) -> Optional[Dict]:        if zone_hint and zone_hint in self.ZONES_BASE:            return self.ZONES_BASE[zone_hint]        for zone_num, zone_params in self.ZONES_BASE.items():            offsets = self.ZONE_OFFSETS.get(zone_num)            if not offsets:                continue            x_full = offsets['offset_x'] + x            y_full = offsets['offset_y'] + y            x_sk42 = x_full + offsets['dx']            y_sk42 = y_full + offsets['dy']            lat = x_sk42 / 111000            y_local = y_sk42 - (int(zone_num) * 1000000)            lon = zone_params['central_meridian'] + (y_local / 85000)            if 55.5 <= lat <= 58.5 and 30 <= lon <= 38:                logger.info(f"Detected zone {zone_num}: lat={lat:.4f}, lon={lon:.4f}")                return zone_params        logger.warning("Cannot detect zone, using zone 6 as default")        return self.ZONES_BASE.get('6')    def get_all_zones(self) -> List[str]:        return list(self.ZONES_BASE.keys())    def get_all_sheets(self) -> List[str]:        return [sheet['sheet'] for sheet in self.TVER_SHEETS]def get_zone_params(zone_number: str) -> Optional[Dict]:    collector = ZoneParamsCollector()    return collector.get_zone_params(zone_number)def get_zone_offsets(zone_number: str) -> Optional[Dict]:    collector = ZoneParamsCollector()    return collector.get_zone_offsets(zone_number)def get_sheet_params(sheet_name: str) -> Optional[Dict]:    collector = ZoneParamsCollector()    return collector.get_sheet_params(sheet_name)def detect_zone_by_coords(x: float, y: float, zone_hint: str = None) -> Optional[Dict]:    collector = ZoneParamsCollector()    return collector.detect_zone_by_coordinates(x, y, zone_hint)def calculate_coordinates(x: float, y: float, zone_number: str, sheet_name: str = None) -> Dict:    collector = ZoneParamsCollector()    return collector.calculate_coordinates(x, y, zone_number, sheet_name)def get_all_zones() -> List[str]:    collector = ZoneParamsCollector()    return collector.get_all_zones()def get_all_sheets() -> List[str]:    collector = ZoneParamsCollector()    return collector.get_all_sheets()